        {"id": "c7", "q": "Молярная масса H2SO4 равна?", "o": ["49 г/моль", "98 г/моль", "196 г/моль", "100 г/моль"], "a": 1, "e": "M = 2*1 + 32 + 4*16 = 98 г/моль.", "t": "Основные понятия", "d": 1},
        {"id": "c8", "q": "Какая связь в молекуле H2O?", "o": ["Ионная", "Ковалентная полярная", "Ковалентная неполярная", "Металлическая"], "a": 1, "e": "Вода - ковалентная полярная связь (разные элементы - H и O).", "t": "Химическая связь", "d": 1},
        {"id": "c9", "q": "Сколько атомов в 1 моле H2O?", "o": ["6*10^23", "1.8*10^24", "3*10^23", "12*10^23"], "a": 1, "e": "1 моль H2O = 6*10^23 молекул. В каждой 3 атома. Итого 1.8*10^24.", "t": "Количество вещества", "d": 2},
        {"id": "c10", "q": "Какой газ выделяется при взаимодействии цинка с HCl?", "o": ["Кислород", "Водород", "Хлор", "Хлороводород"], "a": 1, "e": "Zn + 2HCl = ZnCl2 + H2↑", "t": "Неорганическая химия", "d": 1},
        {"id": "c11", "q": "Сколько неспаренных электронов у атома азота в основном состоянии?", "o": ["1", "2", "3", "4"], "a": 2, "e": "Азот: 1s2 2s2 2p3. На p-подуровне 3 неспаренных электрона.", "t": "Строение атома", "d": 2},
        {"id": "c12", "q": "Как изменится скорость реакции при повышении температуры на 30°C (γ=2)?", "o": ["Увеличится в 2 раза", "Увеличится в 4 раза", "Увеличится в 8 раз", "Увеличится в 16 раз"], "a": 2, "e": "Правило Вант-Гоффа: v2/v1 = γ^(ΔT/10) = 2^3 = 8.", "t": "Химическая кинетика", "d": 3},
        {"id": "c13", "q": "Формула серной кислоты?", "o": ["H2SO3", "H2SO4", "H2S", "SO3"], "a": 1, "e": "Серная кислота - H2SO4.", "t": "Основные понятия", "d": 1},
        {"id": "c14", "q": "Какая среда в растворе Na2CO3?", "o": ["Нейтральная", "Кислая", "Щелочная", "Зависит"], "a": 2, "e": "Na2CO3 - соль сильного основания и слабой кислоты, гидролиз по аниону, среда щелочная.", "t": "Гидролиз", "d": 3},
        {"id": "c15", "q": "Что такое изомеры?", "o": ["Вещества с разным составом", "Вещества с одинаковым составом, разным строением", "Одинаковые вещества", "Разные формы одного элемента"], "a": 1, "e": "Изомеры - вещества с одинаковым составом, но разным строением.", "t": "Органическая химия", "d": 2},
        {"id": "c16", "q": "Качественная реакция на углекислый газ?", "o": ["Известковая вода мутнеет", "Лакмус краснеет", "Запах тухлых яиц", "Горит синим пламенем"], "a": 0, "e": "CO2 + Ca(OH)2 = CaCO3↓ + H2O (муть).", "t": "Неорганическая химия", "d": 2},
    
        {"id": "c17", "q": "Какой элемент имеет электронную конфигурацию 1s2 2s2 2p6 3s2?", "o": ["Ne", "Na", "Mg", "Al"], "a": 2, "e": "12 электронов = магний (Mg).", "t": "Строение атома", "d": 2},
        {"id": "c18", "q": "m(NaCl) = 11.7 г. Найдите количество вещества (M=58.5 г/моль).", "o": ["0.1 моль", "0.2 моль", "0.5 моль", "1 моль"], "a": 1, "e": "n = m/M = 11.7/58.5 = 0.2 моль.", "t": "Количество вещества", "d": 2},
    
        {"id": "c19", "q": "Какой элемент имеет 15 протонов?", "o": ["Si", "P", "S", "Cl"], "a": 1, "e": "Фосфор (P) - 15 протонов.", "t": "Строение атома", "d": 1},
