        {"id": "c21", "q": "Сколько моль в 36 г воды (H2O, M=18 г/моль)?", "o": ["1 моль", "2 моль", "3 моль", "4 моль"], "a": 1, "e": "n=m/M=36/18=2 моль.", "t": "Количество вещества", "d": 1},
        {"id": "c22", "q": "В каком соединении степень окисления серы +6?", "o": ["H2S", "SO2", "H2SO4", "Na2S"], "a": 2, "e": "В H2SO4 у S степень +6.", "t": "ОВР", "d": 2},
        {"id": "c23", "q": "Какая среда у раствора CH3COOH?", "o": ["Нейтральная", "Кислая", "Щелочная", "Нельзя определить"], "a": 1, "e": "Уксусная кислота - слабая кислота, среда кислая.", "t": "Электролиты", "d": 2},
        {"id": "c24", "q": "Какой объём занимают 2 моль газа при н.у.?", "o": ["22.4 л", "44.8 л", "67.2 л", "89.6 л"], "a": 1, "e": "V=n*Vm=2*22.4=44.8 л.", "t": "Количество вещества", "d": 1},
